interface IMultiFunctionDevice { void Print(); void Scan(); void Fax(); }
class SimplePrinter : IMultiFunctionDevice {
  public void Print() { /* imprime */ }
  public void Scan() => throw new NotSupportedException();
  public void Fax()  => throw new NotSupportedException();
}
